4070	static void weights_bind(
4071	        ds4_weights     *w,
4072	        const ds4_model *m,
4073	        bool             load_slice,
4074	        uint32_t         load_layer_start,
4075	        uint32_t         load_layer_end,
4076	        bool             require_output,
4077	        bool             optional_output) {
4078	    memset(w, 0, sizeof(*w));
