4082	    bool require_token_embd = true;
4083	    if (load_slice) {
4084	        if (load_layer_start >= DS4_N_LAYER) ds4_die("invalid model load layer slice");
4085	        start = load_layer_start;
4086	        end = load_layer_end == UINT32_MAX ? DS4_N_LAYER - 1u : load_layer_end;
4087	        if (end >= DS4_N_LAYER || end < start) ds4_die("invalid model load layer slice");
4088	        require_token_embd = start == 0;
